import numpy as np

# Initialize the board with pieces
def initialize_board():
    board = np.zeros((8, 8), dtype=int)
    for row in range(3):
        for col in range(8): 
            if (row + col) % 2 == 1:
                board[row, col] = -1
    for row in range(5, 8):
        for col in range(8): 
            if (row + col) % 2 == 1:
                board[row, col] = 1
    return board

# Print the board with symbols
def print_board(board):
    symbols = {0: '.', -1: 'X', 1: 'O'}
    for row in range(8):
        for col in range(8):
            print(symbols[board[row, col]], end='')
        print()

# Move a piece from one position to another
def move_piece(board, from_pos, to_pos):
    board[to_pos] = board[from_pos]
    board[from_pos] = 0

# Get all possible moves for a player
def get_possible_moves(board, player):
    moves = []
    for row in range(8):
        for col in range(8):
            if board[row, col] == player:
                new_row, new_col = row + (2 * int(player == 1) - 1), col + (1 if player == 1 else -1)
                if 0 <= new_row < 8 and 0 <= new_col < 8 and board[new_row, new_col] == 0:
                    moves.append((row, col, new_row, new_col))
    return moves

# Check if a move is valid
def is_valid_move(board, from_pos, to_pos):
    return (to_pos in get_possible_moves(board, board[from_pos]))

# Main game loop
def play_game():
    board = initialize_board()
    current_player = 1
    while True:
        print_board(board)
        move_input = input(f'Player {current_player}, enter your move (e.g., 0-0 2-2): ').split()
        from_pos, to_pos = tuple(map(int, move_input[0].split('-'))), tuple(map(int, move_input[1].split('-')))
        if is_valid_move(board, from_pos, to_pos):
            move_piece(board, from_pos, to_pos)
            current_player *= -1
        else:
            print('Invalid move. Try again.')

if __name__ == '__main__':
    play_game()"
